property_tests.invariant_check:
for any code, redirectURI:
  capturedBody = intercepted POST body
  assert capturedBody contains 'grant_type=authorization_code'

edge_case_tests.assertion_pseudocode:
// Variant 1: no @ sign
info, err = p.GetUserInfo("valid-token") // server returns {"email": "invalidemail"}
assert info == nil
assert err != nil

// Variant 2: empty local part
info, err = p.GetUserInfo("valid-token") // server returns {"email": "@gmail.com"}
assert info == nil
assert err != nil
